INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('punjabi','Punjabi','north_indian',NULL,'Punjab','Butter-heavy tandoor-centric. Dal makhani, butter chicken, sarson ka saag, chole bhature.','tier_1',true,true) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('kashmiri','Kashmiri','north_indian',NULL,'J&K','Wazwan tradition. Rogan josh, dum aloo, yakhni. Fennel, dry ginger, saffron.','tier_2',true,true) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('rajasthani','Rajasthani','north_indian',NULL,'Rajasthan','Desert cuisine. Dal baati churma, gatte ki sabzi, laal maas. Heavy ghee.','tier_2',true,true) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('himachali','Himachali','north_indian',NULL,'Himachal Pradesh','Mountain cuisine. Dham thali, madra, siddu. Yogurt-based gravies.','tier_3',false,false) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('uttarakhandi','Uttarakhandi','north_indian',NULL,'Uttarakhand','Garhwali + Kumaoni. Kafuli, chainsoo, bhatt ki churkani. Lentil-heavy.','tier_3',false,false) ON CONFLICT (name) DO NOTHING;
