INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('up','UP (General)','north_indian',NULL,'Uttar Pradesh','Broader UP home cooking. Tahiri, bedmi puri, baati chokha, kachori-sabzi.','tier_1',true,true) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('bihari','Bihari','north_indian',NULL,'Bihar','Litti chokha, sattu paratha, thekua, dal pitha. Sattu-centric, mustard oil.','tier_2',true,true) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('bundelkhandi','Bundelkhandi','north_indian',NULL,'Bundelkhand (MP/UP)','Rustic. Bafla, maheri, lapsi.','tier_3',false,false) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('sindhi','Sindhi','north_indian',NULL,'Sindh (diaspora)','Dal pakwan, sindhi kadhi, sai bhaji, koki. Gram flour heavy, tamarind-forward.','tier_2',true,true) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('tamil','Tamil','south_indian',NULL,'Tamil Nadu','Rice-centric, tamarind-forward. Sambar, rasam, poriyal, kootu.','tier_1',true,true) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('chettinad','Chettinad','south_indian','tamil','TN (Karaikudi)','Fiery merchant cuisine. Chettinad chicken, kuzhambu. Unique spices.','tier_2',true,true) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('kerala','Kerala','south_indian',NULL,'Kerala','Coconut-everything. Appam-stew, fish molee, avial, puttu-kadala, sadya.','tier_1',true,true) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('malabar','Malabar','south_indian','kerala','Kerala (North)','Muslim-influenced Kerala. Malabar biryani, pathiri.','tier_2',true,true) ON CONFLICT (name) DO NOTHING;
