INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('udupi','Udupi','south_indian','karnataka','Karnataka (Udupi)','Temple cuisine. Masala dosa, set dosa, sambar. Strictly vegetarian.','tier_2',true,true) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('mangalorean','Mangalorean','south_indian','karnataka','Karnataka (Mangalore)','Coastal. Kori rotti, fish gassi, neer dosa. Seafood-heavy.','tier_2',true,true) ON CONFLICT (name) DO NOTHING;
