INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('odia','Odia','east_indian',NULL,'Odisha','Temple-influenced. Dalma, pakhala bhaat, chhena poda. Light, less oily.','tier_2',true,true) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('assamese','Assamese','east_indian',NULL,'Assam','Khar, masor tenga, aloo pitika. Minimal oil, fermented ingredients, bhut jolokia.','tier_2',true,true) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('jharkhandi','Jharkhandi','east_indian',NULL,'Jharkhand','Tribal/Adivasi. Dhuska, rugra. Forest ingredients, rustic.','tier_3',false,false) ON CONFLICT (name) DO NOTHING;
INSERT INTO public.cuisines (name,display_name,cuisine_group,parent_cuisine,state_origin,description,tier,is_user_facing,is_active) VALUES ('maharashtrian','Maharashtrian','west_indian',NULL,'Maharashtra','Vada pav, misal pav, puran poli, thalipeeth. Peanut + coconut base.','tier_1',true,true) ON CONFLICT (name) DO NOTHING;
